// Render the email body to a minimal PDF that easybits can ingest.
// Pure JavaScript, zero dependencies, runs on n8n Cloud sandbox.

const item = $input.item.json;

// Pull email content. Prefer plain text; strip HTML if only HTML exists.
let bodyText = item.text || item.snippet || '';
if (!bodyText && item.html) {
  bodyText = item.html
    .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
    .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<\/p>/gi, '\n\n')
    .replace(/<[^>]+>/g, '')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

// Build a header so the extractor sees sender, subject, and date too
const subject = item.subject || '(no subject)';
const from = item.from?.value?.[0]?.address || item.from || '(unknown sender)';
const date = item.date || '';
const header = `From: ${from}\nSubject: ${subject}\nDate: ${date}\n\n`;
const fullText = header + bodyText;

// Escape characters that have special meaning inside a PDF string
const esc = (s) => s.replace(/\\/g, '\\\\').replace(/\(/g, '\\(').replace(/\)/g, '\\)');

// Wrap long lines and split on newlines so the PDF doesn't overflow
const MAX_CHARS_PER_LINE = 95;
const MAX_LINES_PER_PAGE = 55;
const lines = [];
for (const rawLine of fullText.split('\n')) {
  if (rawLine.length === 0) { lines.push(''); continue; }
  for (let i = 0; i < rawLine.length; i += MAX_CHARS_PER_LINE) {
    lines.push(rawLine.slice(i, i + MAX_CHARS_PER_LINE));
  }
}

// Split lines across pages
const pages = [];
for (let i = 0; i < lines.length; i += MAX_LINES_PER_PAGE) {
  pages.push(lines.slice(i, i + MAX_LINES_PER_PAGE));
}
if (pages.length === 0) pages.push(['(empty email body)']);

// Build content streams (one per page)
const contentStreams = pages.map((pageLines) => {
  const body = pageLines.map((line, idx) => {
    if (idx === 0) return `BT /F1 11 Tf 50 780 Td (${esc(line)}) Tj`;
    return `T* (${esc(line)}) Tj`;
  }).join('\n') + '\nET';
  return `q\n14 TL\n${body}\nQ`;
});

// Assemble the PDF
const objects = [];
const addObj = (content) => { objects.push(content); return objects.length; };

const catalogId = addObj('<< /Type /Catalog /Pages 2 0 R >>');
const pagesId = addObj(null); // placeholder, fill in below
const fontId = addObj('<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>');

const pageIds = [];
const contentIds = [];
for (const stream of contentStreams) {
  const contentId = addObj(`<< /Length ${stream.length} >>\nstream\n${stream}\nendstream`);
  contentIds.push(contentId);
  const pageId = addObj(`<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] /Resources << /Font << /F1 ${fontId} 0 R >> >> /Contents ${contentId} 0 R >>`);
  pageIds.push(pageId);
}

// Fill pages object
objects[pagesId - 1] = `<< /Type /Pages /Kids [${pageIds.map((id) => `${id} 0 R`).join(' ')}] /Count ${pageIds.length} >>`;

// Build the PDF byte string
let pdf = '%PDF-1.4\n';
const offsets = [];
for (let i = 0; i < objects.length; i++) {
  offsets.push(pdf.length);
  pdf += `${i + 1} 0 obj\n${objects[i]}\nendobj\n`;
}
const xrefOffset = pdf.length;
pdf += `xref\n0 ${objects.length + 1}\n0000000000 65535 f \n`;
for (const off of offsets) {
  pdf += `${String(off).padStart(10, '0')} 00000 n \n`;
}
pdf += `trailer\n<< /Size ${objects.length + 1} /Root ${catalogId} 0 R >>\nstartxref\n${xrefOffset}\n%%EOF`;

// Convert to binary buffer
const pdfBuffer = Buffer.from(pdf, 'binary');

return {
  json: {
    email_id: item.id,
    subject: subject,
    from: from,
    date: date,
    has_attachment: !!(item.attachments && item.attachments.length > 0),
  },
  binary: {
    ...$input.item.binary,
    bodyPdf: await this.helpers.prepareBinaryData(pdfBuffer, 'body.pdf', 'application/pdf'),
  },
};

// True branch: email has at least one PDF attachment.
// 1. Stash the body extraction result so it survives the next Extractor call
// 2. Promote the first PDF attachment to a standard binary key the Extractor can read

const item = $input.item;
const bodyExtraction = item.json.data || {};

// Find the first PDF attachment (skip bodyPdf — that's our rendered email body)
const attachmentEntry = Object.entries(item.binary || {})
  .find(([key, value]) =>
    key !== 'bodyPdf' &&
    (value.mimeType === 'application/pdf' || (value.fileName || '').toLowerCase().endsWith('.pdf'))
  );

if (!attachmentEntry) {
  // Safety net — shouldn't happen because the IF already filtered, but just in case
  throw new Error('No PDF attachment found despite IF branch routing here. Check the IF node logic.');
}

const [attachmentKey, attachmentBinary] = attachmentEntry;

return {
  json: {
    // Preserve everything from upstream
    ...item.json,
    // Stash the body extraction under a separate key so the next Extractor doesn't overwrite it
    bodyData: bodyExtraction,
    attachment_filename: attachmentBinary.fileName || 'attachment.pdf',
  },
  binary: {
    // Promote the attachment to a known key for the next Extractor node
    attachmentPdf: attachmentBinary,
    // Keep bodyPdf around in case we want it later (e.g. for debugging or archival)
    bodyPdf: item.binary.bodyPdf,
  },
};

// Merge the body and attachment extractions (when both exist) and stage a
// clean row for the Google Sheets ledger.
//
// Branch awareness:
//   - If item has `json.bodyData`, this came from the True branch (both
//     extractions ran). Merge with body priority, attachment as fallback.
//   - Otherwise, this came from the False branch (body extraction only).
//     Use it as-is.

const item = $input.item.json;
// Pull email metadata directly from the upstream "Prepare: Email Body" node.
// The Extractor overwrites $json with its own {data: ...} envelope, so by the
// time we get here the email metadata staged in Node 2 has been lost — except
// when the True branch's "Prepare: Attachment Binary" explicitly stashed it.
const emailMeta = $('Prepare: Email Body').item.json;

// Helper: the Extractor returns the literal string "null" for missing fields,
// not real JSON null. Treat both as missing.
const isMissing = (v) =>
  v === null ||
  v === undefined ||
  v === 'null' ||
  (typeof v === 'string' && v.trim() === '');

// Helper: pick body value if present, fall back to attachment value
const prefer = (bodyVal, attachVal) =>
  isMissing(bodyVal) ? (isMissing(attachVal) ? null : attachVal) : bodyVal;

// Determine which branch we came from
const cameFromTrueBranch = !!item.bodyData;

let merged;
if (cameFromTrueBranch) {
  const body = item.bodyData || {};
  const attach = item.data || {};
  merged = {
    vendor: prefer(body.vendor, attach.vendor),
    amount: prefer(body.amount, attach.amount),
    currency: prefer(body.currency, attach.currency),
    plan_name: prefer(body.plan_name, attach.plan_name),
    billing_period: prefer(body.billing_period, attach.billing_period),
    invoice_date: prefer(body.invoice_date, attach.invoice_date),
  };
} else {
  const body = item.data || {};
  merged = {
    vendor: isMissing(body.vendor) ? null : body.vendor,
    amount: isMissing(body.amount) ? null : body.amount,
    currency: isMissing(body.currency) ? null : body.currency,
    plan_name: isMissing(body.plan_name) ? null : body.plan_name,
    billing_period: isMissing(body.billing_period) ? null : body.billing_period,
    invoice_date: isMissing(body.invoice_date) ? null : body.invoice_date,
  };
}

// Coerce amount to a number (the Extractor sometimes returns it as a string)
if (merged.amount !== null) {
  const parsed = parseFloat(String(merged.amount).replace(/,/g, ''));
  merged.amount = isNaN(parsed) ? null : parsed;
}

// Normalize vendor: lowercase, trim, strip common suffixes (belt and braces —
// the Extractor description already asks for this, but never trust it 100%)
if (merged.vendor !== null) {
  merged.vendor = String(merged.vendor)
    .toLowerCase()
    .trim()
    .replace(/\s+(inc|llc|ltd|gmbh|sa|sas|corp|co)\.?$/i, '')
    .replace(/[.,]$/, '');
}

// Required-field check: skip rows that are unusable
if (isMissing(merged.vendor) || merged.amount === null) {
  throw new Error(
    `Skipping receipt: missing vendor (${merged.vendor}) or amount (${merged.amount}). ` +
    `Email: "${emailMeta.subject}" from ${emailMeta.from}. ` +
    `Check the Extractor output — body may be empty or attachment may have unusual format.`
  );
}

return {
  json: {
    // Ledger columns (matches Google Sheets schema)
    date: merged.invoice_date || new Date().toISOString().slice(0, 10),
    vendor: merged.vendor,
    amount: merged.amount,
    currency: merged.currency || 'USD',
    plan_name: merged.plan_name || '',
    billing_period: merged.billing_period || '',
    source_label: 'historical',
    email_id: emailMeta.email_id,
    // Useful debug context (won't be written to the sheet unless we map it)
    email_subject: emailMeta.subject,
    email_from: emailMeta.from,
    merge_source: cameFromTrueBranch ? 'body+attachment' : 'body-only',
  },
};
